// GormRepository implements the users domain repository interface using GORM
type GormRepository struct {
	db *gorm.DB
}

type authenticatedUserRow struct {
	Username           string
	UserType           string
	Password           string
	MustChangePassword bool
}

// NewGormRepository creates a new GORM-based users repository
func NewGormRepository(db *gorm.DB) *GormRepository {
	return &GormRepository{db: db}
}

// GetByUsername retrieves a user by username
func (r *GormRepository) GetByUsername(ctx context.Context, username string) (*dusers.User, error) {
	var dbUser models.User

	err := r.db.WithContext(ctx).Where("username = ?", username).First(&dbUser).Error
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dusers.ErrUserNotFound
		}
		return nil, err
	}

	return r.modelToDomain(&dbUser), nil
}

func (r *GormRepository) UsernameExists(ctx context.Context, username string) (bool, error) {
	return r.userFieldExists(ctx, "username", username)
}

func (r *GormRepository) DisplayNameExists(ctx context.Context, displayName string) (bool, error) {
	return r.userFieldExists(ctx, "display_name", displayName)
}

func (r *GormRepository) EmailExists(ctx context.Context, email string) (bool, error) {
	return r.userFieldExists(ctx, "email", email)
}

func (r *GormRepository) APIKeyExists(ctx context.Context, apiKey string) (bool, error) {
	return r.userFieldExists(ctx, "api_key", apiKey)
}

func (r *GormRepository) userFieldExists(ctx context.Context, field string, value string) (bool, error) {
	var count int64
	if err := r.db.WithContext(ctx).Model(&models.User{}).Where(field+" = ?", value).Count(&count).Error; err != nil {
		return false, err
	}
	return count > 0, nil
}

func (r *GormRepository) AnyUserIdentityExists(ctx context.Context, username, displayName, email, apiKey string) (bool, error) {
	var count int64
	if err := r.db.WithContext(ctx).Model(&models.User{}).Where(
		"username = ? OR display_name = ? OR email = ? OR api_key = ?",
		username, displayName, email, apiKey,
	).Count(&count).Error; err != nil {
		return false, err
	}
	return count > 0, nil
}

// UpdateBalance updates a user's account balance
func (r *GormRepository) UpdateBalance(ctx context.Context, username string, newBalance int64) error {
	result := r.db.WithContext(ctx).Model(&models.User{}).
		Where("username = ?", username).
		Update("account_balance", newBalance)

	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// Create creates a new user in the database
func (r *GormRepository) Create(ctx context.Context, user *dusers.User) error {
	dbUser := r.domainToModel(user)

	result := r.db.WithContext(ctx).Create(&dbUser)
	if result.Error != nil {
		// Check for unique constraint violations
		if errors.Is(result.Error, gorm.ErrDuplicatedKey) {
			return dusers.ErrUserAlreadyExists
		}
		return result.Error
	}

	// Update the domain model with the generated ID
	user.ID = dbUser.ID
	return nil
}

// Update updates a user in the database
func (r *GormRepository) Update(ctx context.Context, user *dusers.User) error {
	dbUser := r.domainToModel(user)

	result := r.db.WithContext(ctx).Save(&dbUser)
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// Delete removes a user from the database
func (r *GormRepository) Delete(ctx context.Context, username string) error {
	result := r.db.WithContext(ctx).Where("username = ?", username).Delete(&models.User{})
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// List retrieves users with the given filters
func (r *GormRepository) List(ctx context.Context, filters dusers.ListFilters) ([]*dusers.User, error) {
	query := r.db.WithContext(ctx).Model(&models.User{})

	if filters.UserType != "" {
		query = query.Where("user_type = ?", filters.UserType)
	}

	if filters.Limit > 0 {
		query = query.Limit(filters.Limit)
	}

	if filters.Offset > 0 {
		query = query.Offset(filters.Offset)
	}

	query = query.Order("created_at DESC")

	var dbUsers []models.User
	if err := query.Find(&dbUsers).Error; err != nil {
		return nil, err
	}

	users := make([]*dusers.User, len(dbUsers))
	for i, dbUser := range dbUsers {
		users[i] = r.modelToDomain(&dbUser)
	}

	return users, nil
}

// ListUserBets retrieves all bets placed by the specified user ordered by placement time descending.
func (r *GormRepository) ListUserBets(ctx context.Context, username string) ([]*dusers.UserBet, error) {
	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("username = ?", username).
		Order("placed_at DESC").
		Find(&bets).Error; err != nil {
		return nil, err
	}

	result := make([]*dusers.UserBet, len(bets))
	for i, bet := range bets {
		result[i] = &dusers.UserBet{
			MarketID: bet.MarketID,
			PlacedAt: bet.PlacedAt,
		}
	}
	return result, nil
}

